import json

import train


def main():
    values = [train.train_once()["accuracy"] for _ in range(3)]
    stable = max(values) - min(values) <= 1e-12
    print(json.dumps({
        "accuracy": float(sum(values) / len(values)),
        "reproducibility_score": 1.0 if stable else 0.0,
    }))


if __name__ == "__main__":
    main()

